package org.eclipse.rdf4j.http.client;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.verify;

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.junit.jupiter.api.Test;

class AsyncTraceCoordinatorTest {

	@Test
	void registerShouldRejectDuplicateTraceRequestIds() {
		AsyncTraceCoordinator coordinator = new AsyncTraceCoordinator();
		coordinator.register("req-1");

		assertThatThrownBy(() -> coordinator.register("req-1"))
				.isInstanceOf(IllegalStateException.class)
				.hasMessage("Trace request already active: req-1");
	}

	@Test
	void cancelBeforeExecuteShouldSkipTraceOperation() throws Exception {
		AsyncTraceCoordinator coordinator = new AsyncTraceCoordinator();
		AsyncTraceCoordinator.Handle handle = coordinator.register("req-2");
		RepositoryConnection connection = mock(RepositoryConnection.class);
		AtomicInteger scopeClosed = new AtomicInteger();

		assertThat(coordinator.cancel("req-2")).isTrue();
		Object result = coordinator.execute(handle, connection, ignored -> scopeClosed::incrementAndGet, () -> {
			throw new AssertionError("trace operation should not execute after cancellation");
		});
		assertThat(result).isNull();

		assertThat(handle.isActive()).isFalse();
		assertThat(scopeClosed).hasValue(1);
	}

	@Test
	void cancelShouldInterruptCloseConnectionAndForwardRemoteCancel() throws Exception {
		AsyncTraceCoordinator coordinator = new AsyncTraceCoordinator();
		AtomicInteger remoteCancelCalls = new AtomicInteger();
		AsyncTraceCoordinator.Handle handle = coordinator.register("req-3", remoteCancelCalls::incrementAndGet);
		RepositoryConnection connection = mock(RepositoryConnection.class);
		ExecutorService executor = Executors.newSingleThreadExecutor();
		CountDownLatch entered = new CountDownLatch(1);

		try {
			Future<String> future = executor.submit(() -> coordinator.execute(handle, connection, () -> {
				entered.countDown();
				try {
					new CountDownLatch(1).await();
					return "completed";
				} catch (InterruptedException e) {
					return "interrupted";
				}
			}));

			assertThat(entered.await(5, TimeUnit.SECONDS)).isTrue();
			assertThat(coordinator.cancel("req-3")).isTrue();
			assertThat(future.get(5, TimeUnit.SECONDS)).isNull();

			verify(connection).close();
			assertThat(remoteCancelCalls).hasValue(1);
			assertThat(handle.isActive()).isFalse();
		} finally {
			executor.shutdownNow();
		}
	}

	@Test
	void completeShouldRemoveHandleFromCoordinator() {
		AsyncTraceCoordinator coordinator = new AsyncTraceCoordinator();
		AsyncTraceCoordinator.Handle handle = coordinator.register("req-4");

		coordinator.complete(handle);

		assertThat(handle.isActive()).isFalse();
		assertThat(coordinator.cancel("req-4")).isFalse();
	}

	@Test
	void executeShouldCloseTraceScopeWhenOperationFails() {
		AsyncTraceCoordinator coordinator = new AsyncTraceCoordinator();
		AsyncTraceCoordinator.Handle handle = coordinator.register("req-4b");
		RepositoryConnection connection = mock(RepositoryConnection.class);
		AtomicInteger scopeClosed = new AtomicInteger();
		RuntimeException boom = new RuntimeException("boom");

		assertThatThrownBy(
				() -> coordinator.execute(handle, connection, ignored -> scopeClosed::incrementAndGet, () -> {
					throw boom;
				}))
				.isSameAs(boom);

		assertThat(scopeClosed).hasValue(1);
		assertThat(handle.isActive()).isTrue();
	}

	@Test
	void cancelShouldSwallowConnectionAndRemoteCancelFailures() throws Exception {
		AsyncTraceCoordinator coordinator = new AsyncTraceCoordinator();
		AsyncTraceCoordinator.Handle handle = coordinator.register("req-4c", () -> {
			throw new IllegalStateException("remote cancel");
		});
		RepositoryConnection connection = mock(RepositoryConnection.class);
		ExecutorService executor = Executors.newSingleThreadExecutor();
		CountDownLatch entered = new CountDownLatch(1);
		doThrow(new RuntimeException("close")).when(connection).close();

		try {
			Future<String> future = executor.submit(() -> coordinator.execute(handle, connection, () -> {
				entered.countDown();
				try {
					new CountDownLatch(1).await();
					return "completed";
				} catch (InterruptedException e) {
					return "interrupted";
				}
			}));

			assertThat(entered.await(5, TimeUnit.SECONDS)).isTrue();
			assertThat(coordinator.cancel("req-4c")).isTrue();
			assertThat(future.get(5, TimeUnit.SECONDS)).isNull();

			verify(connection).close();
			assertThat(handle.isActive()).isFalse();
		} finally {
			executor.shutdownNow();
		}
	}

	@Test
	void shutdownShouldCancelAllRegisteredHandles() {
		AsyncTraceCoordinator coordinator = new AsyncTraceCoordinator();
		AtomicInteger remoteCancelCalls = new AtomicInteger();

		AsyncTraceCoordinator.Handle first = coordinator.register("req-5a", remoteCancelCalls::incrementAndGet);
		AsyncTraceCoordinator.Handle second = coordinator.register("req-5b", remoteCancelCalls::incrementAndGet);

		coordinator.shutdown();

		assertThat(first.isActive()).isFalse();
		assertThat(second.isActive()).isFalse();
		assertThat(remoteCancelCalls).hasValue(2);
		assertThat(coordinator.cancel("req-5a")).isFalse();
		assertThat(coordinator.cancel("req-5b")).isFalse();
	}
}
